<?php
require_once __DIR__ . '/bootstrap.php'; require_auth(); $pdo=db();
if(method()==='GET'){ $tripId=int_param('trip_id'); $eventId=int_param('event_id'); if(!$tripId)json_response(['error'=>'Missing trip_id'],400); if($eventId){$s=$pdo->prepare('SELECT * FROM documents WHERE trip_id=? AND event_id=? ORDER BY uploaded_at DESC');$s->execute([$tripId,$eventId]);}else{$s=$pdo->prepare('SELECT * FROM documents WHERE trip_id=? ORDER BY uploaded_at DESC');$s->execute([$tripId]);} json_response($s->fetchAll()); }
if(method()==='POST'){ $tripId=(int)($_POST['trip_id']??0); $eventId=(isset($_POST['event_id'])&&$_POST['event_id']!=='')?(int)$_POST['event_id']:null; $notes=clean_string($_POST['notes']??null,5000); if(!$tripId)json_response(['error'=>'Missing trip_id'],400); if(empty($_FILES['file']))json_response(['error'=>'Missing file'],400); $file=$_FILES['file']; if($file['error']!==UPLOAD_ERR_OK)json_response(['error'=>'Upload error'],400); if($file['size']>MAX_UPLOAD_BYTES)json_response(['error'=>'File too large'],400); if(!allowed_upload_extension($file['name']))json_response(['error'=>'File type not allowed'],400); $ext=strtolower(pathinfo($file['name'],PATHINFO_EXTENSION)); $stored=bin2hex(random_bytes(16)).'.'.$ext; $uploadDir=realpath(__DIR__.'/../uploads'); if(!$uploadDir)json_response(['error'=>'Upload directory missing'],500); $target=$uploadDir.DIRECTORY_SEPARATOR.$stored; if(!move_uploaded_file($file['tmp_name'],$target))json_response(['error'=>'Could not store file'],500); $relative='uploads/'.$stored; $mime=mime_content_type($target)?:null; $s=$pdo->prepare('INSERT INTO documents (trip_id,event_id,original_filename,stored_filename,file_path,mime_type,file_size,notes) VALUES (?,?,?,?,?,?,?,?)'); $s->execute([$tripId,$eventId,clean_string($file['name'],255)?:'file',$stored,$relative,$mime,(int)$file['size'],$notes]); json_response(['id'=>(int)$pdo->lastInsertId()],201); }
if(method()==='DELETE'){ $id=int_param('id'); if(!$id)json_response(['error'=>'Missing id'],400); $s=$pdo->prepare('SELECT * FROM documents WHERE id=?');$s->execute([$id]);$doc=$s->fetch(); if($doc){$path=realpath(__DIR__.'/../'.$doc['file_path']);$uploadDir=realpath(__DIR__.'/../uploads'); if($path&&$uploadDir&&str_starts_with($path,$uploadDir)&&file_exists($path))unlink($path); $d=$pdo->prepare('DELETE FROM documents WHERE id=?');$d->execute([$id]);} json_response(['ok'=>true]); }
json_response(['error'=>'Method not allowed'],405);
